var sumIndicesWithKSetBits = function(nums, k) {
    let total = 0;
    for (let i = 0; i < nums.length; i++) {
        let c = 0;
        let x = i;
        while (x) {
            c += x & 1;
            x >>= 1;
        }
        if (c === k) total += nums[i];
    }
    return total;
};
